import{c as e,Q as r,j as c,m as t}from"./chunks/framework.hhGiamYR.js";const n=JSON.parse('{"title":"第一章　探究了马基雅维利在《君主论》中对博尔贾的论述如何与圣经相一致。他用了比书中其他人物都要多的篇幅来讨论博尔贾——或者是“瓦伦蒂诺公爵”这个马基雅维利和“群氓”都宁可采用的称谓。我认为，在详细叙述博尔贾生涯的过程中，马基雅维利始终广泛使用圣经寓言，这告诉我们：即使在君主国内，马基雅维利还是会认为，普通人一定要充当政治现实的终极仲裁者；尽管有时候他会说，君主的美德意味着不受约束的自治，但通过准基督主义的瓦伦蒂诺的例子，马基雅维利实际上表明了，审慎的君主必须在自己和臣民之间培养相互依赖的关系——一种因使得共同对手流血而被神圣化的关系。因此，这一章要质疑那种认为马基雅维利的目标是使政治彻底去神学化的观点；实际上，[208]我认为，对马基雅维利而言，所有政治的确立都必须通过准宗教术语而得到神圣化，以确保人民的“精神”能够接受“好政府”的好处。","description":"","frontmatter":{},"headers":[],"relativePath":"research/machiavelli/scholarship/mccormick/01-第一章.md","filePath":"research/machiavelli/scholarship/mccormick/01-第一章.md"}'),p={name:"research/machiavelli/scholarship/mccormick/01-第一章.md"};function s(i,a,o,_,l,m){return r(),c("div",null,[...a[0]||(a[0]=[t("",9)])])}const d=e(p,[["render",s]]);export{n as __pageData,d as default};
